const data = $.steps.scrapePage.response.data || $.steps.scrapePage.response || {};
const markdown = data.markdown || data.content || '';
const links = data.links || [];
const metadata = data.metadata || {};
const title = metadata.title || data.title || $.input.url;
const description = metadata.description || '';
const wordCount = markdown.split(/\s+/).length;

// Truncate content to a reasonable size for the prompt
const content = markdown.slice(0, 12000);

return { content, title, description, wordCount, linkCount: links.length };

const prompt = `You are a content analyst. Summarize the following webpage content into a structured, easy-to-read summary.

PAGE TITLE: ${$.steps.extractContent.output.title}
PAGE URL: ${$.input.url}
WORD COUNT: ${$.steps.extractContent.output.wordCount}
DESCRIPTION: ${$.steps.extractContent.output.description}

PAGE CONTENT:
${$.steps.extractContent.output.content}

INSTRUCTIONS:
- Create a comprehensive yet concise summary
- Identify key takeaways and main arguments
- Note any data points, statistics, or notable quotes
- Use Slack mrkdwn formatting: *bold* (NOT **bold**), _italic_, > for quotes, numbered lists
- Slack mrkdwn rules: No markdown tables. No # headings.

Return ONLY valid JSON:
{
  "summary": "<2-4 paragraph summary using Slack mrkdwn>",
  "keyTakeaways": ["<takeaway 1>", "<takeaway 2>", "<takeaway 3>"],
  "mainTopics": ["<topic 1>", "<topic 2>"],
  "notableQuotes": ["<quote if any>"],
  "sentiment": "positive|neutral|negative|mixed",
  "readingTimeMinutes": <estimated reading time of original>
}`;

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, keyTakeaways: [], mainTopics: [], notableQuotes: [], sentiment: 'neutral', readingTimeMinutes: 0 }; }

const ai = $.steps.parseAI.output || {};
const title = $.steps.extractContent.output.title;
const url = $.input.url;
const wordCount = $.steps.extractContent.output.wordCount;

const sentimentEmoji = ai.sentiment === 'positive' ? ':slightly_smiling_face:' : ai.sentiment === 'negative' ? ':slightly_frowning_face:' : ai.sentiment === 'mixed' ? ':thinking_face:' : ':neutral_face:';

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Webpage Summary' } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + title + '*\n<' + url + '|View original>' } });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary*\n' + summaryText } });
blocks.push({ type: 'divider' });

if (ai.keyTakeaways && ai.keyTakeaways.length > 0) {
  let takeaways = '*Key Takeaways:*\n';
  ai.keyTakeaways.forEach((t, i) => { takeaways += (i+1) + '. ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: takeaways } });
  blocks.push({ type: 'divider' });
}

if (ai.notableQuotes && ai.notableQuotes.length > 0) {
  let quotes = '*Notable Quotes:*\n';
  ai.notableQuotes.forEach(q => { quotes += '> ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: quotes } });
  blocks.push({ type: 'divider' });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: sentimentEmoji + ' Sentiment: *' + (ai.sentiment || 'neutral') + '* | Words: *' + wordCount + '* | Est. reading time: *' + (ai.readingTimeMinutes || '?') + ' min*' }] });

const fallback = 'Summary of: ' + title + ' (' + url + ')';

return { blocks, fallback };
